func solve(n int64, edges [][]int64, label string) int64 {
    // Build adjacency list
    adj := make(map[int64][]int64)
    for _, edge := range edges {
        u, v := edge[0], edge[1]
        adj[u] = append(adj[u], v)
        adj[v] = append(adj[v], u)
    }

    // Use BFS to find the longest palindrome path
    maxLength := int64(0)

    // Start from each node
    for start := int64(0); start < n; start++ {
        queue := [][3][]int64{{start, 0, []int64{start}}}
        visited := make(map[int64]bool)
        visited[start] = true

        for len(queue) > 0 {
            node, depth, path := queue[0][0], queue[0][1], queue[0][2]
            queue = queue[1:]

            // Check if the current path forms a palindrome
            if depth > 0 {
